/* BTModal — centered dialog with backdrop, header, optional content, optional footer.
   Figma D-Modal: 2123:1992 (web) · M-Modal: 2124:2190 (mobile).
   Shared between @btech/ui-vue and @btech/ui-react — keep these files identical. */

/* ── Backdrop / overlay ──────────────────────────────────────────────────── */

.bt-modal-backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  /* Raw rgba allowed (CLAUDE.md §6) — opacity overlay, not a named token. */
  background: rgba(0, 0, 0, 0.5);
  z-index: 9000;
  padding: 24px;
}

/* ── Panel ───────────────────────────────────────────────────────────────── */

.bt-modal-panel {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 100%;
  max-height: calc(100vh - 48px);
  background: var(--bg-primary);
  border-radius: var(--radius-md);
  overflow: hidden;
  box-shadow: 0 16px 32px rgba(0, 0, 0, 0.16);
  font-family: var(--typography-font-family-sans);
  color: var(--text-primary);
}

.bt-modal-panel--sm { max-width: 500px; }
.bt-modal-panel--md { max-width: 720px; }
.bt-modal-panel--lg { max-width: 1042px; }

/* ── Header (white section) ──────────────────────────────────────────────── */

.bt-modal-header {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 16px;
  background: var(--bg-primary);
}

.bt-modal-title {
  font-size: 18px;
  font-weight: 700;
  line-height: 1.4;
  color: var(--text-primary);
  margin: 0;
  padding-right: 32px; /* leave room for X button */
}

.bt-modal-subtext {
  font-size: 14px;
  font-weight: 500;
  line-height: 1.4;
  color: var(--text-secondary);
  margin: 0;
}

.bt-modal-close {
  position: absolute;
  top: 16px;
  right: 16px;
  width: 24px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  border-radius: 4px;
  padding: 0;
  transition: background 0.12s ease, color 0.12s ease;
}

.bt-modal-close:hover {
  background: var(--bg-subtle);
  color: var(--text-primary);
}

.bt-modal-close:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 1px;
}

/* ── Content slot (still in white section) ────────────────────────────────── */

.bt-modal-content {
  padding: 0 16px 16px;
  background: var(--bg-primary);
  overflow-y: auto;
  font-size: 14px;
  color: var(--text-primary);
}

/* ── Footer (grey subtle section) ─────────────────────────────────────────── */

.bt-modal-footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 8px;
  padding: 12px 16px;
  background: var(--bg-subtle);
  border-top: 1px solid var(--border-primary);
}

.bt-modal-footer__left {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-right: auto;
}

.bt-modal-footer__checkbox {
  width: 16px;
  height: 16px;
  margin: 0;
  cursor: pointer;
  accent-color: var(--color-brand-primary);
}

.bt-modal-footer__checkbox-label {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-primary);
  cursor: pointer;
  user-select: none;
}

.bt-modal-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 12px 16px;
  border-radius: var(--radius-sm);
  border: none;
  font-family: inherit;
  font-size: 12px;
  font-weight: 500;
  line-height: 1;
  cursor: pointer;
  transition: opacity 0.12s ease, filter 0.12s ease;
}

.bt-modal-btn:hover { filter: brightness(0.96); }
.bt-modal-btn:active { filter: brightness(0.92); }

.bt-modal-btn--secondary {
  background: var(--bg-secondary);
  color: var(--text-primary);
}

.bt-modal-btn--primary {
  background: var(--color-brand-primary);
  color: var(--text-inverse);
}

.bt-modal-btn:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

/* ── Animations (Vue Transition + React keyframes share these) ─────────────── */

.bt-modal-enter-active { transition: opacity 0.2s ease; }
.bt-modal-leave-active { transition: opacity 0.15s ease; }
.bt-modal-enter-from,
.bt-modal-leave-to { opacity: 0; }

.bt-modal-enter-active .bt-modal-panel {
  transition: opacity 0.2s ease, transform 0.2s ease;
}
.bt-modal-leave-active .bt-modal-panel {
  transition: opacity 0.15s ease, transform 0.15s ease;
}
.bt-modal-enter-from .bt-modal-panel,
.bt-modal-leave-to .bt-modal-panel {
  opacity: 0;
  transform: scale(0.95) translateY(8px);
}

@keyframes bt-modal-backdrop-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes bt-modal-panel-in {
  from { opacity: 0; transform: scale(0.95) translateY(8px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

.bt-modal-backdrop--animated {
  animation: bt-modal-backdrop-in 0.2s ease forwards;
}

.bt-modal-backdrop--animated .bt-modal-panel {
  animation: bt-modal-panel-in 0.2s ease forwards;
}

/**
 * BTModal — centred dialog with backdrop, header, optional content, footer.
 *
 * Figma: D-Modal 2123:1992 (web) · M-Modal 2124:2190 (mobile).
 *
 * @example
 * ```tsx
 * import { useState } from 'react';
 * import { BTModal } from '@btech/ui-react';
 *
 * export function Example() {
 *   const [open, setOpen] = useState(false);
 *   return (
 *     <>
 *       <button onClick={() => setOpen(true)}>Open</button>
 *       <BTModal
 *         open={open}
 *         title="Confirm action"
 *         subtext="Are you sure you want to continue?"
 *         size="md"
 *         onPrimary={() => setOpen(false)}
 *         onSecondary={() => setOpen(false)}
 *         onClose={() => setOpen(false)}
 *       >
 *         <p>Optional content goes here.</p>
 *       </BTModal>
 *     </>
 *   );
 * }
 * ```
 */
import { useEffect, useState, type ReactNode } from 'react';
import { createPortal } from 'react-dom';
import './BTModal.css';
import type { BTModalProps } from './BTModal.types';

interface BTModalReactProps extends BTModalProps {
  children?: ReactNode;
  onPrimary?: () => void;
  onSecondary?: () => void;
  onClose?: () => void;
  onCheckbox?: (checked: boolean) => void;
}

export function BTModal({
  open,
  title,
  subtext,
  size = 'sm',
  hasClose = true,
  hasFooter = true,
  primaryLabel = 'Confirm',
  hasSecondaryButton = true,
  secondaryLabel = 'Cancel',
  hasCheckbox = false,
  checkboxLabel = "Don't show again",
  dismissable = true,
  children,
  onPrimary,
  onSecondary,
  onClose,
  onCheckbox,
}: BTModalReactProps) {
  const [checked, setChecked] = useState(false);

  // ── Body scroll lock ─────────────────────────────────────────────────────
  useEffect(() => {
    if (typeof document === 'undefined') return;
    if (open) {
      const prev = document.body.style.overflow;
      document.body.style.overflow = 'hidden';
      return () => {
        document.body.style.overflow = prev;
      };
    }
    return undefined;
  }, [open]);

  if (!open) return null;
  if (typeof document === 'undefined') return null;

  const close = (): void => {
    onClose?.();
  };

  const handleBackdropClick = (e: React.MouseEvent<HTMLDivElement>): void => {
    if (e.target !== e.currentTarget) return;
    if (dismissable) close();
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    setChecked(e.target.checked);
    onCheckbox?.(e.target.checked);
  };

  return createPortal(
    <div
      className="bt-modal-backdrop bt-modal-backdrop--animated"
      onClick={handleBackdropClick}
    >
      <div className={`bt-modal-panel bt-modal-panel--${size}`} role="dialog" aria-modal="true">
        {/* Header */}
        <div className="bt-modal-header">
          <h2 className="bt-modal-title">{title}</h2>
          {subtext && <p className="bt-modal-subtext">{subtext}</p>}
          {hasClose && (
            <button
              type="button"
              className="bt-modal-close"
              aria-label="Close"
              onClick={close}
            >
              <svg width="16" height="16" viewBox="0 0 16 16" aria-hidden="true">
                <path
                  d="M3.5 3.5 L12.5 12.5 M12.5 3.5 L3.5 12.5"
                  stroke="currentColor"
                  strokeWidth="1.6"
                  strokeLinecap="round"
                />
              </svg>
            </button>
          )}
        </div>

        {/* Optional content */}
        {children && <div className="bt-modal-content">{children}</div>}

        {/* Footer */}
        {hasFooter && (
          <div className="bt-modal-footer">
            {hasCheckbox && (
              <div className="bt-modal-footer__left">
                <input
                  id="bt-modal-checkbox"
                  type="checkbox"
                  className="bt-modal-footer__checkbox"
                  checked={checked}
                  onChange={handleCheckboxChange}
                />
                <label htmlFor="bt-modal-checkbox" className="bt-modal-footer__checkbox-label">
                  {checkboxLabel}
                </label>
              </div>
            )}
            {hasSecondaryButton && (
              <button
                type="button"
                className="bt-modal-btn bt-modal-btn--secondary"
                onClick={() => onSecondary?.()}
              >
                {secondaryLabel}
              </button>
            )}
            <button
              type="button"
              className="bt-modal-btn bt-modal-btn--primary"
              onClick={() => onPrimary?.()}
            >
              {primaryLabel}
            </button>
          </div>
        )}
      </div>
    </div>,
    document.body,
  );
}

/**
 * BTModal — type definitions.
 *
 * A centred modal dialog with a header (title + optional subtext + optional
 * close button), an optional content slot, and an optional footer with
 * checkbox + secondary/primary actions. Backdrop overlay with click-to-
 * dismiss when [dismissable] is true.
 */

/** Width preset — sm = 500 px, md = 720 px, lg = 1042 px. */
export type BTModalSize = 'sm' | 'md' | 'lg';

export interface BTModalProps {
  /** Whether the modal is visible. */
  open: boolean;
  /** Bold title shown at the top of the header. */
  title: string;
  /** Optional supporting text shown below the title. */
  subtext?: string;
  /** Width preset. @default 'sm' */
  size?: BTModalSize;
  /** Show the X button in the top-right of the header. @default true */
  hasClose?: boolean;
  /** Show the footer section. @default true */
  hasFooter?: boolean;
  /** Label for the right-most primary action button. @default 'Confirm' */
  primaryLabel?: string;
  /** Show the secondary (cancel) button next to the primary one. @default true */
  hasSecondaryButton?: boolean;
  /** Label for the secondary action button. @default 'Cancel' */
  secondaryLabel?: string;
  /** Show a checkbox at the left of the footer. @default false */
  hasCheckbox?: boolean;
  /** Label rendered next to the footer checkbox. @default "Don't show again" */
  checkboxLabel?: string;
  /** Click on backdrop closes the modal. @default true */
  dismissable?: boolean;
}
